import bcrypt from 'bcryptjs';
import { Payment } from './entities/payment.entity'
import { PaymentMethod } from './enums/payment-method.enum'
import { PaymentStatus } from './enums/payment-status.enum'
import { format } from 'date-fns';

export async function processPaymentAsync(payment: Payment, cardToken: string | null): Promise<void> {
  payment.status = PaymentStatus.Processing;
  await this.paymentRepository.save(payment);
  let success: boolean = false;
  let error: string | null = null;
  let gatewayResponse: string | null = null;
  try {
    if (((payment.method === PaymentMethod.CreditCard) || (payment.method === PaymentMethod.DebitCard))) {
      const result: Record<string, unknown> = stripeGateway.charge({amount: (payment.amount.amount * 100), currency: payment.amount.currency.value.toLowerCase(), source: cardToken, metadata: {transactionId: payment.transactionId, orderId: String(payment.orderId), customerId: String(payment.customerId)}});
      success = result.success;
      gatewayResponse = JSON.stringify(result);
      if ((!success)) {
        error = (result.error ?? 'Stripe charge failed');
      }
    } else {
      if ((payment.method === PaymentMethod.PayPal)) {
        const result: Record<string, unknown> = payPalGateway.charge({amount: payment.amount, transactionId: payment.transactionId, customerId: payment.customerId});
        success = result.success;
        gatewayResponse = JSON.stringify(result);
        if ((!success)) {
          error = (result.error ?? 'PayPal charge failed');
        }
      } else {
        if ((payment.method === PaymentMethod.BankTransfer)) {
          payment.gatewayResponse = 'Bank transfer initiated - awaiting confirmation';
          await this.paymentRepository.save(payment);
          return;
        } else {
          error = `Unsupported payment method: ${payment.method}`;
        }
      }
    }
  }
  catch (e: unknown) {
    success = false;
    error = `Payment gateway error: ${e.message}`;
    console.error('payment_processing_exception');;
  }
  if (success) {
    payment.status = PaymentStatus.Completed;
    payment.processedAt = new Date();
    payment.gatewayResponse = gatewayResponse;
  } else {
    payment.status = PaymentStatus.Failed;
    payment.errorMessage = (error ?? 'Payment processing failed');
    payment.gatewayResponse = gatewayResponse;
  }
  await this.paymentRepository.save(payment);
}

export async function hashPassword(password: string): Promise<string> {
  return await bcrypt.hash(password, 10);
}

export async function verifyPassword(password: string, hash: string): Promise<boolean> {
  return await bcrypt.compare(password, hash);
}

export function generateToken(length: number = 32): string {
  return Array.from({ length: length }, () => 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789'.charAt(Math.floor(Math.random() * 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789'.length))).join('');
}

export function generateOrderNumber(): string {
  return `ORD-${format(new Date(), 'YYYYMMDDHHmmss')}-${Array.from({ length: 4 }, () => '0123456789'.charAt(Math.floor(Math.random() * '0123456789'.length))).join('')}`;
}

export function generateTransactionId(): string {
  return `TXN-${format(new Date(), 'YYYYMMDDHHmmss')}-${Array.from({ length: 8 }, () => 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789'.charAt(Math.floor(Math.random() * 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789'.length))).join('')}`;
}

export function generateTrackingNumber(): string {
  return `TRACK-${format(new Date(), 'YYYYMMDD')}-${Array.from({ length: 10 }, () => 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789'.charAt(Math.floor(Math.random() * 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789'.length))).join('').toUpperCase()}`;
}
